function Ymd2Jd(yy,mm,dd) {
	var days,tmp,yym1;
	yym1 = yy - 1;
	days = 1721422;
	solarMonth[1] = 28;
	if (yy % 4 == 0) {
		solarMonth[1] = 29;
		if (yy > 1582) {
			if (yy % 100 == 0) {
				solarMonth[1] = 28;
				if (yy %400 == 0) {
					solarMonth[1] = 29;
				}
			}
		}
	}
	days += Math.floor(365.25 * yym1 + 0.1);
	for (m = 0; m < (mm - 1) ; m++) {
		days += solarMonth[m];
	}
	days += dd;
	if (days >= 2299160) days -= 10;
	if (yym1 >= 1600) {
		days -= Math.floor((yym1 - 1600 + 0.1) / 100);
		days += Math.floor((yym1 - 1600 + 0.1) / 400);
	}
	return days;
}

